import { Theme } from "../Theme/types";

const lightThemeColors = {
  primary: "#e60800",
  background: "#101015",
};

const darkThemeColors = {
  primary: "#2C2C31",
  secondary: "#e60800",
  dark: "#580100",
  text: "#FFEBEB",
  accent: "#2C2C31",
};

export const getColors = (theme: Theme) => {
  return theme === Theme.LIGHT ? lightThemeColors : darkThemeColors;
};
